#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int R, K;
        scanf("%d %d", &R, &K);
        double r = R - K / 100.0;
        int x, y;
        for (x = 1; x * x < r * r; x++) {
            y = sqrt(r * r - x * x);
            if (y == (int)y) {
                printf("%d %d\n", x, (int)y);
                break;
            }
        }
        if (x * x >= r * r) {
            printf("-1\n");
        }
    }
    return 0;
}

