code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int R = sc.nextInt();
            int K = sc.nextInt();
            double r = R - K / 100.0;
            int x, y;
            for (x = 1; x * x < r * r; x++) {
                y = (int) Math.sqrt(r * r - x * x);
                if (y * y == r * r - x * x) {
                    System.out.println(x + " " + y);
                    break;
                }
            }
            if (x * x >= r * r) {
                System.out.println(-1);
            }
        }
    }
}

