    const r = R - K / 100.0;
    for (let x = 1; x * x < r * r; x++) {
        const y = Math.sqrt(r * r - x * x);
        if (y === Math.floor(y)) {
            console.log(x + ' ' + Math.floor(y));
            break;
        }
    }
    if (x * x >= r * r) {
        console.log(-1);
    }
}

